import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useWhisper } from './useWhisper';
import CurrencyVisualizer from './CurrencyVisualizer';
import './CurrencyShowcase.css';

// ── Currency name → ISO code map ─────────────────────────────────
const CURRENCY_MAP = {
  dollar: 'USD', dollars: 'USD', usd: 'USD', 'us dollar': 'USD', 'us dollars': 'USD', 'american dollar': 'USD',
  euro: 'EUR', euros: 'EUR', eur: 'EUR',
  pound: 'GBP', pounds: 'GBP', gbp: 'GBP', sterling: 'GBP', 'british pound': 'GBP', 'british pounds': 'GBP',
  yen: 'JPY', jpy: 'JPY', 'japanese yen': 'JPY',
  yuan: 'CNY', cny: 'CNY', renminbi: 'CNY', rmb: 'CNY', 'chinese yuan': 'CNY',
  rupee: 'INR', rupees: 'INR', inr: 'INR', 'indian rupee': 'INR',
  franc: 'CHF', francs: 'CHF', chf: 'CHF', 'swiss franc': 'CHF',
  won: 'KRW', krw: 'KRW', 'korean won': 'KRW', 'south korean won': 'KRW',
  peso: 'MXN', pesos: 'MXN', mxn: 'MXN', 'mexican peso': 'MXN',
  real: 'BRL', reais: 'BRL', brl: 'BRL', 'brazilian real': 'BRL',
  'canadian dollar': 'CAD', cad: 'CAD', 'canadian dollars': 'CAD',
  'australian dollar': 'AUD', aud: 'AUD', 'australian dollars': 'AUD',
  'new zealand dollar': 'NZD', nzd: 'NZD',
  lira: 'TRY', try: 'TRY', 'turkish lira': 'TRY',
  rand: 'ZAR', zar: 'ZAR', 'south african rand': 'ZAR',
  krona: 'SEK', sek: 'SEK', 'swedish krona': 'SEK',
  krone: 'NOK', nok: 'NOK', 'norwegian krone': 'NOK',
  'danish krone': 'DKK', dkk: 'DKK',
  'singapore dollar': 'SGD', sgd: 'SGD',
  'hong kong dollar': 'HKD', hkd: 'HKD',
  zloty: 'PLN', pln: 'PLN', 'polish zloty': 'PLN',
  forint: 'HUF', huf: 'HUF', 'hungarian forint': 'HUF',
  koruna: 'CZK', czk: 'CZK', 'czech koruna': 'CZK',
  'philippine peso': 'PHP', php: 'PHP',
  baht: 'THB', thb: 'THB', 'thai baht': 'THB',
  ringgit: 'MYR', myr: 'MYR', 'malaysian ringgit': 'MYR',
  rupiah: 'IDR', idr: 'IDR', 'indonesian rupiah': 'IDR',
};

const CURRENCY_SYMBOLS = {
  USD: '$', EUR: '€', GBP: '£', JPY: '¥', CNY: '¥', INR: '₹',
  KRW: '₩', BRL: 'R$', RUB: '₽', TRY: '₺', PLN: 'zł', THB: '฿',
  PHP: '₱', IDR: 'Rp', MYR: 'RM', SAR: '﷼', AED: 'د.إ',
};

const SUGGESTIONS = [
  '100 USD to EUR',
  '50 pounds to dollars',
  '1000 yen to rupees',
  '500 euros to Canadian dollars',
  'convert 200 AUD to GBP',
];

function resolveCurrency(raw) {
  const key = raw.trim().toLowerCase();
  return CURRENCY_MAP[key] || (key.length === 3 ? key.toUpperCase() : null);
}

function formatAmount(n, code) {
  const sym = CURRENCY_SYMBOLS[code] || '';
  const formatted = new Intl.NumberFormat('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: code === 'JPY' || code === 'KRW' || code === 'IDR' ? 0 : 2,
  }).format(n);
  return sym ? `${sym}${formatted}` : `${formatted} ${code}`;
}

function parseQuery(text) {
  const s = text.toLowerCase().replace(/[,]/g, '');
  const names = Object.keys(CURRENCY_MAP)
    .sort((a, b) => b.length - a.length)
    .map(n => n.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
    .join('|');
  const currencyPattern = `(?:${names}|[a-z]{3})`;
  const re = new RegExp(
    `(?:convert|change|exchange)?\\s*(\\d+(?:\\.\\d+)?)\\s+(${currencyPattern})\\s+(?:to|in|into)\\s+(${currencyPattern})`
  );
  const m = s.match(re);
  if (!m) return null;
  const amount = parseFloat(m[1]);
  const from = resolveCurrency(m[2]);
  const to = resolveCurrency(m[3]);
  if (!from || !to || from === to) return null;
  return { amount, from, to };
}

// Frankfurter supported codes (api.frankfurter.dev/v1/currencies)
const SUPPORTED = new Set([
  'AUD','BRL','CAD','CHF','CNY','CZK','DKK','EUR','GBP',
  'HKD','HUF','IDR','ILS','INR','ISK','JPY','KRW','MXN',
  'MYR','NOK','NZD','PHP','PLN','RON','SEK','SGD','THB',
  'TRY','USD','ZAR',
]);

async function fetchConversion(amount, from, to) {
  if (!SUPPORTED.has(from)) throw new Error(`${from} not supported`);
  if (!SUPPORTED.has(to))   throw new Error(`${to} not supported`);
  const res = await fetch(
    `https://api.frankfurter.dev/v1/latest?amount=${amount}&from=${from}&to=${to}`
  );
  if (!res.ok) throw new Error(`API error ${res.status}`);
  const data = await res.json();
  const result = data.rates[to];
  if (result === undefined) throw new Error(`No rate for ${to}`);
  return { result, rate: result / amount, date: data.date };
}

let msgId = 0;
const mkId = () => ++msgId;

const WELCOME = {
  id: mkId(),
  role: 'bot',
  type: 'welcome',
  text: 'Ask me to convert any currency — type or speak naturally.',
};

const MIC_LABEL = {
  idle: 'Speak',
  loading: 'Loading model…',
  recording: 'Stop recording',
  transcribing: 'Transcribing…',
};

export default function CurrencyShowcase() {
  const navigate = useNavigate();
  const [messages, setMessages] = useState([WELCOME]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const chatEndRef = useRef(null);
  const inputRef = useRef(null);

  const addMessage = useCallback((msg) => {
    setMessages(prev => [...prev, { id: mkId(), ...msg }]);
  }, []);

  const handleSend = useCallback(async (text) => {
    const q = (text ?? input).trim();
    if (!q || loading) return;
    setInput('');
    inputRef.current?.focus();

    addMessage({ role: 'user', type: 'text', text: q });

    const parsed = parseQuery(q);
    if (!parsed) {
      addMessage({ role: 'bot', type: 'error', text: 'Try something like "100 USD to EUR" or "50 pounds to yen".' });
      return;
    }

    setLoading(true);
    try {
      const { result, rate, date } = await fetchConversion(parsed.amount, parsed.from, parsed.to);
      addMessage({ role: 'bot', type: 'result', amount: parsed.amount, from: parsed.from, to: parsed.to, result, rate, date });
    } catch (err) {
      const msg = err.message?.includes('not supported')
        ? `${err.message}. Supported currencies include USD, EUR, GBP, JPY, CAD, AUD, INR, CNY, and 22 others.`
        : 'Could not fetch live rate — please try again.';
      addMessage({ role: 'bot', type: 'error', text: msg });
    } finally {
      setLoading(false);
    }
  }, [input, loading, addMessage]);

  const { state: whisperState, loadPct, toggle: toggleMic, analyserRef } = useWhisper({
    onResult: useCallback((text) => {
      setInput(text);
      handleSend(text);
    }, [handleSend]),
    onError: useCallback((msg) => {
      addMessage({ role: 'bot', type: 'error', text: msg });
    }, [addMessage]),
  });

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const micBusy = whisperState !== 'idle';
  const micActive = whisperState === 'recording';

  return (
    <div className="fx-root">
      <CurrencyVisualizer state={whisperState} analyserRef={analyserRef} />
      <button
        className="fx-back-btn"
        onClick={() => navigate('/', { state: { scrollTo: 'projects' } })}
      >← Timeline</button>

      <div className="fx-layout">
        <header className="fx-header">
          <h1>Currency Converter</h1>
          <p>Type or speak — live exchange rates, any pair</p>
        </header>

        <div className="fx-chat">
          {messages.map(msg => (
            <div key={msg.id} className={`fx-msg fx-msg--${msg.role}`}>
              {msg.type === 'welcome' && (
                <div className="fx-bubble">
                  <div>{msg.text}</div>
                  <div className="fx-suggestions">
                    {SUGGESTIONS.map(s => (
                      <button key={s} className="fx-suggestion" onClick={() => handleSend(s)}>{s}</button>
                    ))}
                  </div>
                </div>
              )}
              {msg.type === 'text' && <div className="fx-bubble">{msg.text}</div>}
              {msg.type === 'error' && <div className="fx-bubble fx-error">{msg.text}</div>}
              {msg.type === 'result' && (
                <div className="fx-bubble">
                  <div className="fx-result">
                    <div className="fx-result-amount">
                      {formatAmount(msg.result, msg.to)} <span>{msg.to}</span>
                    </div>
                    <div className="fx-result-rate">
                      {formatAmount(msg.amount, msg.from)} {msg.from} = {formatAmount(msg.result, msg.to)} {msg.to}
                    </div>
                    <div className="fx-result-rate">
                      1 {msg.from} = {msg.rate.toFixed(msg.rate < 0.01 ? 6 : 4)} {msg.to}
                    </div>
                    <div className="fx-result-meta">
                      <span className="fx-result-date">Rate as of {msg.date}</span>
                      <button className="fx-flip-btn" onClick={() => handleSend(`${msg.result.toFixed(2)} ${msg.to} to ${msg.from}`)}>⇄ Reverse</button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          ))}

          {loading && (
            <div className="fx-msg fx-msg--bot">
              <div className="fx-bubble">
                <div className="fx-typing">
                  <div className="fx-dot" /><div className="fx-dot" /><div className="fx-dot" />
                </div>
              </div>
            </div>
          )}

          <div ref={chatEndRef} />
        </div>

        <div className="fx-input-area">
          {whisperState === 'loading' && (
            <div className="fx-transcript">Loading voice model… {loadPct > 0 ? `${loadPct}%` : ''}</div>
          )}
          {whisperState === 'recording' && (
            <div className="fx-transcript fx-transcript--recording">Recording — click mic to stop</div>
          )}
          {whisperState === 'transcribing' && (
            <div className="fx-transcript">Transcribing…</div>
          )}

          <div className="fx-input-row">
            <input
              ref={inputRef}
              className="fx-input"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={micBusy ? MIC_LABEL[whisperState] : 'Convert 100 USD to EUR…'}
              disabled={micBusy}
            />
            <button
              className={`fx-mic${micActive ? ' fx-mic--listening' : ''}${whisperState === 'loading' || whisperState === 'transcribing' ? ' fx-mic--busy' : ''}`}
              onClick={toggleMic}
              disabled={whisperState === 'loading' || whisperState === 'transcribing'}
              title={MIC_LABEL[whisperState]}
            >
              {micActive ? (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                  <rect x="6" y="6" width="12" height="12" rx="2" />
                </svg>
              ) : (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                  <path d="M19 10v2a7 7 0 0 1-14 0v-2H3v2a9 9 0 0 0 8 8.94V23h2v-2.06A9 9 0 0 0 21 12v-2h-2z"/>
                </svg>
              )}
            </button>
            <button
              className="fx-send"
              onClick={() => handleSend()}
              disabled={!input.trim() || loading || micBusy}
              title="Send"
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                <path d="M2 21l21-9L2 3v7l15 2-15 2z"/>
              </svg>
            </button>
          </div>
          <div className="fx-unsupported">
            Voice powered by Whisper — runs locally in your browser, no data sent to any server
          </div>
        </div>
      </div>
    </div>
  );
}
